WARRANTS_HTML = r'''
<!doctype html><html lang="vi"><head><meta charset="UTF-8"/><meta name="viewport" content="width=device-width,initial-scale=1.0"/><title>Chứng quyền - Investment Information</title><style>
:root{--bg:#070b14;--panel:#101726;--panel2:#151f32;--line:rgba(151,170,214,.14);--text:#edf2ff;--muted:#92a0c0;--accent:#64b5ff;--green:#4ef0c0;--red:#ff6b6b;--yellow:#ffda6b}*{box-sizing:border-box}body{margin:0;background:radial-gradient(circle at top,#101a2e,#070b14 45%,#05070d);color:var(--text);font-family:Inter,Segoe UI,Arial,sans-serif}a{color:inherit;text-decoration:none}.shell{width:min(1120px,calc(100% - 24px));margin:0 auto;padding:14px 0 36px}.topbar{display:flex;align-items:center;justify-content:space-between;gap:12px;padding:14px 16px;border:1px solid var(--line);background:rgba(9,14,24,.9);border-radius:22px;position:sticky;top:10px;z-index:5}.brand{display:flex;align-items:center;gap:12px}.logo{width:44px;height:44px;border-radius:14px;display:grid;place-items:center;background:linear-gradient(135deg,var(--accent),#7a74ff);font-weight:800}.brand h1{font-size:22px;margin:0}.brand p{margin:3px 0 0;color:var(--muted);font-size:12px;letter-spacing:.16em}.tabs,.actions{display:flex;gap:10px;flex-wrap:wrap}.tabs{margin:14px 0}.chip,.btn{border:1px solid var(--line);background:var(--panel2);padding:10px 14px;border-radius:999px;color:var(--muted);font-weight:700;cursor:pointer}.btn{color:var(--text);border-radius:12px}.chip.active{background:rgba(100,181,255,.16);color:var(--text);border-color:rgba(100,181,255,.35)}.danger{background:rgba(255,107,107,.12);color:#ffb0b0}.panel{border:1px solid var(--line);background:rgba(16,23,38,.9);border-radius:24px;padding:18px}.head{margin-bottom:14px}.head h3{margin:0;font-size:24px}.head p{margin:6px 0 0;color:var(--muted)}.search{display:flex;gap:10px;flex-wrap:wrap;margin-bottom:14px}.wrap{position:relative;flex:1;min-width:230px}input{width:100%;background:var(--panel2);color:var(--text);border:1px solid var(--line);border-radius:14px;padding:12px 14px}.suggest{position:absolute;left:0;right:0;top:calc(100% + 8px);z-index:10;background:#0c1322;border:1px solid var(--line);border-radius:14px;display:none;overflow:hidden}.suggest.open{display:block}.option{padding:11px 13px;border-bottom:1px solid var(--line);cursor:pointer}.option:hover{background:rgba(100,181,255,.12)}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(190px,1fr));gap:12px}.card{border:1px solid var(--line);background:rgba(21,31,50,.82);border-radius:18px;padding:14px;cursor:pointer}.card strong{display:flex;justify-content:space-between;gap:8px;font-size:18px}.badge{font-size:11px;padding:4px 8px;border-radius:999px}.itm{background:rgba(78,240,192,.15);color:var(--green)}.atm{background:rgba(255,218,107,.15);color:var(--yellow)}.otm{background:rgba(255,107,107,.15);color:#ffb0b0}.row{display:flex;justify-content:space-between;gap:12px;margin-top:9px;color:var(--muted)}.row b{color:var(--text)}.up{color:var(--green)!important}.down{color:var(--red)!important}.flat{color:var(--yellow)!important}.modal{position:fixed;inset:0;background:rgba(2,6,14,.72);display:none;align-items:center;justify-content:center;padding:18px;z-index:50}.modal.open{display:flex}.box{width:min(760px,100%);max-height:90vh;overflow:auto;border:1px solid var(--line);background:#101726;border-radius:24px;padding:18px}.boxhead{display:flex;justify-content:space-between;gap:12px;align-items:flex-start;margin-bottom:14px}.box h3{margin:0;font-size:32px}.muted{color:var(--muted)}.summary{display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:10px;margin-bottom:12px}.metric{background:var(--panel2);border:1px solid var(--line);border-radius:16px;padding:12px}.metric span{display:block;color:var(--muted);font-size:12px}.metric b{font-size:20px}.table{border:1px solid var(--line);border-radius:16px;overflow:hidden}.trow{display:flex;justify-content:space-between;gap:12px;padding:11px 13px;border-bottom:1px solid var(--line)}.trow:last-child{border-bottom:0}.disclaimer{margin-top:16px;border:1px solid var(--line);border-radius:18px;padding:12px;color:var(--muted);font-size:13px}
</style></head><body><div class="shell"><header class="topbar"><a class="brand" href="/stocks"><div class="logo">H</div><div><h1>Investment Information</h1><p>HOA INVESTMENT</p></div></a><span class="chip active" id="apiStatus">Online</span></header><nav class="tabs"><a class="chip" href="/stocks">Chứng Khoán</a><a class="chip active" href="/warrants">Chứng Quyền</a><a class="chip" href="/news-page">Tin Tức</a></nav><main class="panel"><div class="head"><h3>Danh mục chứng quyền quan tâm</h3><p id="status">Đang tải dữ liệu chứng quyền...</p></div><div class="search"><div class="wrap"><input id="search" placeholder="Tìm mã chứng quyền, ví dụ: CMWG2511..." autocomplete="off"><div class="suggest" id="suggest"></div></div><div class="actions"><button class="btn" id="addBtn">Thêm</button><button class="btn danger" id="removeBtn">Xóa khỏi danh mục</button></div></div><div class="grid" id="grid"></div></main><div class="disclaimer"><b>Lưu ý:</b> Dữ liệu chỉ phục vụ tham khảo, không phải khuyến nghị mua bán.</div></div><div class="modal" id="modal"><div class="box"><div class="boxhead"><div><h3 id="title">CW</h3><p class="muted" id="sub"></p></div><div class="actions"><button class="btn" id="detailAdd">Thêm vào danh mục</button><button class="btn danger" id="detailRemove">Xóa</button><button class="btn" id="closeBtn">Đóng</button></div></div><div id="stats"></div></div></div><script>
const API_BASE=''; let items=[],watch=[],selected=''; const $=id=>document.getElementById(id); const esc=s=>String(s??'').replaceAll('&','&amp;').replaceAll('<','&lt;').replaceAll('>','&gt;').replaceAll('"','&quot;').replaceAll("'",'&#39;'); const num=(v,d=2)=>{const n=Number(v);return Number.isFinite(n)?n.toLocaleString('vi-VN',{maximumFractionDigits:d,minimumFractionDigits:d}):'-'}; const price=v=>{const n=Number(v);return Number.isFinite(n)?n.toLocaleString('vi-VN',{maximumFractionDigits:0}):'-'}; const vol=v=>{const n=Number(v);return Number.isFinite(n)?n.toLocaleString('vi-VN'): '-'}; const cls=v=>Number(v)>0?'up':Number(v)<0?'down':'flat'; const badge=s=>String(s).toUpperCase()==='ITM'?'itm':String(s).toUpperCase()==='ATM'?'atm':'otm';
function read(){try{return JSON.parse(localStorage.getItem('hoa.warrants.watchlist')||'[]').map(x=>String(x).toUpperCase())}catch{return[]}} function write(){localStorage.setItem('hoa.warrants.watchlist',JSON.stringify(watch))}
function render(){const display=items.filter(x=>watch.includes(String(x.code||'').toUpperCase())); $('status').textContent=display.length?`Đang hiển thị ${display.length} mã chứng quyền`:'Chưa có mã chứng quyền trong danh mục. Anh search mã rồi bấm Thêm.'; $('grid').innerHTML=display.length?display.map(x=>{const c=cls(x.changePct),sg=Number(x.changePct)>0?'+':'';return `<div class="card" data-code="${esc(x.code)}"><strong>${esc(x.code)}<span class="badge ${badge(x.moneyness)}">${esc(x.moneyness||'-')}</span></strong><div class="row"><span>Giá hiện tại</span><b class="${c}">${esc(price(x.marketPrice||x.lastPrice||x.fairValue))}</b></div><div class="row"><span>% thay đổi</span><b class="${c}">${sg}${esc(num(x.changePct))}%</b></div></div>`}).join(''):'<div class="card muted">Chưa có mã chứng quyền trong danh mục.</div>'}
async function detail(code){code=String(code||'').toUpperCase(); if(!code)return null; let item=items.find(x=>String(x.code||'').toUpperCase()===code); if(!item||!item.marketPrice){const r=await fetch(`${API_BASE}/warrants-data?symbols=${encodeURIComponent(code)}&ts=${Date.now()}`,{cache:'no-store'}); if(r.ok){const d=await r.json(); const got=(d.items||[])[0]; if(got){const i=items.findIndex(x=>String(x.code||'').toUpperCase()===code); if(i>=0)items[i]={...items[i],...got,code}; else items.push({...got,code}); item=items.find(x=>String(x.code||'').toUpperCase()===code)}}} return item}
async function openDetail(code,push=true){const x=await detail(code); if(!x)return; selected=String(x.code).toUpperCase(); const c=cls(x.changePct),sg=Number(x.changePct)>0?'+':''; $('title').textContent=x.code; $('sub').textContent=`${x.underlying||'-'} • ${x.moneyness||'-'}`; $('detailAdd').textContent=watch.includes(selected)?'Đã thêm':'Thêm vào danh mục'; $('stats').innerHTML=`<div class="summary"><div class="metric"><span>Giá hiện tại</span><b class="${c}">${esc(price(x.marketPrice||x.lastPrice||x.fairValue))}</b></div><div class="metric"><span>% thay đổi</span><b class="${c}">${sg}${esc(num(x.changePct))}%</b></div><div class="metric"><span>Mã cơ sở</span><b>${esc(x.underlying||'-')}</b></div></div><div class="table"><div class="trow"><span>Giá cơ sở</span><b>${esc(price(x.underlyingPrice))}</b></div><div class="trow"><span>Giá thực hiện</span><b>${esc(price(x.exercisePrice))}</b></div><div class="trow"><span>Hòa vốn</span><b>${esc(price(x.breakeven))}</b></div><div class="trow"><span>Chênh hòa vốn</span><b>${Number(x.breakevenGap||0)>0?'+':''}${esc(price(x.breakevenGap))} (${Number(x.breakevenGapPct||0)>0?'+':''}${esc(num(x.breakevenGapPct))}%)</b></div><div class="trow"><span>Đòn bẩy</span><b>${esc(num(x.leverage))}x</b></div><div class="trow"><span>Bid / Ask</span><b>${esc(price(x.bid))} / ${esc(price(x.ask))}</b></div><div class="trow"><span>Spread</span><b>${esc(num(x.spreadPct))}%</b></div><div class="trow"><span>Volume</span><b>${esc(vol(x.volume))}</b></div><div class="trow"><span>Rủi ro</span><b>${esc(x.riskLevel||'-')}</b></div><div class="trow"><span>Tín hiệu</span><b>${esc(x.advancedSignal||'-')}</b></div><div class="trow"><span>Đáo hạn</span><b>${esc(x.maturityDate||'-')}</b></div><div class="trow"><span>Còn lại</span><b>${esc(x.daysLeft??'-')} ngày</b></div></div>`; $('modal').classList.add('open'); if(push&&location.pathname!==`/warrants/${selected}`)history.pushState({},'',`/warrants/${selected}`)}
function search(){const q=$('search').value.trim().toUpperCase(); selected=''; if(!q){$('suggest').classList.remove('open');$('suggest').innerHTML='';return} const found=items.filter(x=>String(x.code||'').includes(q)||String(x.underlying||'').includes(q)).slice(0,20); $('suggest').innerHTML=found.map(x=>`<div class="option" data-code="${esc(x.code)}"><b>${esc(x.code)}</b><span class="muted"> ${esc(x.underlying||'')} • ${esc(x.maturityDate||'-')}</span></div>`).join(''); $('suggest').classList.toggle('open',found.length>0)}
async function add(){const code=String(selected||$('search').value).trim().toUpperCase(); if(!code)return; await detail(code); if(!watch.includes(code))watch.unshift(code); write(); $('search').value=''; selected=''; render(); if($('modal').classList.contains('open'))$('detailAdd').textContent='Đã thêm'} function remove(){const code=String(selected||$('search').value||$('title').textContent).trim().toUpperCase(); watch=watch.filter(x=>x!==code); write(); render(); $('modal').classList.remove('open'); if(location.pathname.startsWith('/warrants/'))history.pushState({},'','/warrants')}
async function init(){watch=read(); const r=await fetch(`${API_BASE}/warrants-data?ts=${Date.now()}`,{cache:'force-cache'}); const d=await r.json(); items=(d.items||[]).map(x=>({...x,code:String(x.code||'').toUpperCase()})); render(); const refresh=watch.slice(0,6); if(refresh.length){const rr=await fetch(`${API_BASE}/warrants-data?symbols=${encodeURIComponent(refresh.join(','))}&ts=${Date.now()}`,{cache:'no-store'}); if(rr.ok){const dd=await rr.json(); (dd.items||[]).forEach(x=>{const code=String(x.code||'').toUpperCase(); const i=items.findIndex(y=>String(y.code||'').toUpperCase()===code); if(i>=0)items[i]={...items[i],...x,code}; else items.push({...x,code})}); render()}} const parts=location.pathname.split('/').filter(Boolean); if(parts[1])openDetail(parts[1],false)}
$('search').oninput=search; $('suggest').onclick=e=>{const o=e.target.closest('[data-code]'); if(o){selected=o.dataset.code;$('search').value=selected;$('suggest').classList.remove('open');openDetail(selected)}}; $('grid').onclick=e=>{const c=e.target.closest('[data-code]'); if(c)openDetail(c.dataset.code)}; $('addBtn').onclick=add; $('removeBtn').onclick=remove; $('detailAdd').onclick=add; $('detailRemove').onclick=remove; $('closeBtn').onclick=()=>{$('modal').classList.remove('open'); if(location.pathname.startsWith('/warrants/'))history.pushState({},'','/warrants')}; $('modal').onclick=e=>{if(e.target===$('modal'))$('closeBtn').click()}; window.onpopstate=()=>{const parts=location.pathname.split('/').filter(Boolean); if(parts[0]==='warrants'&&parts[1])openDetail(parts[1],false); else $('modal').classList.remove('open')}; init();
</script></body></html>
'''
